      "keystrokes": "python3 << 'PYEOF'
import os, re, glob

files = sorted(glob.glob('/app/ocr/frame_*.txt'))

def parse_frame(text):
    lines = text.strip().split('\n')
    prompts = []
    moves_counter = None
    for line in lines:
        m = re.search(r'Moves:\s*(\d+)', line)
        if m:
            moves_counter = int(m.group(1))
        if '>' in line:
            idx = line.rindex('>')
            cmd = line[idx+1:].strip()
            prompts.append(cmd)
    return prompts, moves_counter

frame_data = []
for f in files:
    text = open(f).read()
    prompts, counter = parse_frame(text)
    frame_data.append({
        'file': os.path.basename(f),
        'prompts': prompts,
        'counter': counter
    })

# Track new completed commands by comparing consecutive frames
moves = []
prev_all = []

for fd in frame_data:
    cur_all = fd['prompts']

    # Find first position where they differ
    min_len = min(len(prev_all), len(cur_all))
    first_diff = min_len
    for i in range(min_len):
        if prev_all[i] != cur_all[i]:
            first_diff = i
            break

    # New completed commands are from first_diff to len(cur_all)-2 (excluding last = being typed)
    for i in range(first_diff, len(cur_all) - 1):
        cmd = cur_all[i].strip()
        if cmd:
            moves.append(cmd)

    prev_all = cur_all

for i, move in enumerate(moves):
    print(f"{i+1}: {move!r}")

print(f"\nTotal moves: {len(moves)}")
print(f"Final counter: {frame_data[-1]['counter']}")
PYEOF
